import React, { useState, useEffect } from 'react';
import { Stage, Layer } from 'react-konva';
import Spaceship from './Spaceship';
import Background from './Background';
import Bullet from './Bullet';
import Enemy from './Enemy';

const Game = () => {
    const [spaceshipPosition, setSpaceshipPosition] = useState({ x: (window.innerWidth * 0.8) / 2 - 25, y: window.innerHeight * 0.8 - 60 });
    const [bullets, setBullets] = useState([]);
    const [enemies, setEnemies] = useState([]);

    const handleKeyDown = (e) => {
        if (e.key === 'ArrowLeft') {
            setSpaceshipPosition((pos) => ({ ...pos, x: Math.max(pos.x - 10, 0) }));
        } else if (e.key === 'ArrowRight') {
            setSpaceshipPosition((pos) => ({ ...pos, x: Math.min(pos.x + 10, window.innerWidth * 0.8 - 50) }));
        } else if (e.key === ' ') {
            setBullets((prevBullets) => [
                ...prevBullets,
                { x: spaceshipPosition.x + 25, y: spaceshipPosition.y },
            ]);
        }
    };

    useEffect(() => {
        window.addEventListener('keydown', handleKeyDown);
        return () => {
            window.removeEventListener('keydown', handleKeyDown);
        };
    }, []);

    useEffect(() => {
        const gameLoop = () => {
            // Düşman ve mermi güncellemeleri
            requestAnimationFrame(gameLoop);
        };
        requestAnimationFrame(gameLoop);
    }, []);

    return (
        <Stage width={window.innerWidth * 0.8} height={window.innerHeight * 0.8}>
            <Layer>
                <Background />
                <Spaceship x={spaceshipPosition.x} y={spaceshipPosition.y} />
                {bullets.map((bullet, index) => (
                    <Bullet key={index} x={bullet.x} y={bullet.y} />
                ))}
                {enemies.map((enemy, index) => (
                    <Enemy key={index} x={enemy.x} y={enemy.y} />
                ))}
            </Layer>
        </Stage>
    );
};

export default Game;
